  1→import { desc, eq, sql } from "drizzle-orm";
  2→import { db } from "../db";
  3→import { jobs, scrapeResults } from "../db/schema";
  4→
  5→// ========== Types ==========
  6→
  7→export type ScrapeResult = typeof scrapeResults.$inferSelect;
  8→
  9→export type GetHistoryOptions = {
 10→  platform?: string;
 11→  limit?: number;
 12→};
 13→
 14→export type PlatformStats = {
 15→  platform: string;
 16→  totalRuns: number;
 17→  successCount: number;
 18→  failedCount: number;
 19→  successRate: number;
 20→  totalJobsFound: number;
 21→  totalJobsNew: number;
 22→  totalDuplicates: number;
 23→  avgDurationMs: number;
 24→};
 25→
 26→export type ScrapeAnalytics = {
 27→  totalRuns: number;
 28→  totalJobsFound: number;
 29→  totalJobsNew: number;
 30→  totalDuplicates: number;
 31→  totalUniqueJobs: number;
 32→  overallSuccessRate: number;
 33→  avgDurationMs: number;
 34→  byPlatform: PlatformStats[];
 35→};
 36→
 37→export type TimeSeriesPoint = {
 38→  date: string;
 39→  platform: string;
 40→  jobsFound: number;
 41→  jobsNew: number;
 42→  duplicates: number;
 43→  successCount: number;
 44→  failedCount: number;
 45→  totalRuns: number;
 46→  avgDurationMs: number;
 47→};
 48→
 49→export type GetTimeSeriesOptions = {
 50→  startDate?: Date;
 51→  endDate?: Date;
 52→  platform?: string;
 53→  groupBy?: "day" | "week";
 54→};
 55→
 56→// ========== Service Functions ==========
 57→
 58→/** Scrape resultaten ophalen, optioneel gefilterd op platform en gelimiteerd */
 59→export async function getHistory(opts: GetHistoryOptions = {}): Promise<ScrapeResult[]> {
 60→  const limit = Math.min(opts.limit ?? 50, 100);
 61→
 62→  const baseQuery = db.select().from(scrapeResults);
 63→  const filtered = opts.platform
 64→    ? baseQuery.where(eq(scrapeResults.platform, opts.platform))
 65→    : baseQuery;
 66→
 67→  return filtered.orderBy(desc(scrapeResults.runAt)).limit(limit);
 68→}
 69→
 70→/** Bereken analytics per platform over alle scrape resultaten */
 71→export async function getAnalytics(): Promise<ScrapeAnalytics> {
 72→  const rows = await db
 73→    .select({
 74→      platform: scrapeResults.platform,
 75→      totalRuns: sql<number>`count(*)::int`,
 76→      successCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'success')::int`,
 77→      failedCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
 78→      totalJobsFound: sql<number>`coalesce(sum(${scrapeResults.jobsFound}), 0)::int`,
 79→      totalJobsNew: sql<number>`coalesce(sum(${scrapeResults.jobsNew}), 0)::int`,
 80→      totalDuplicates: sql<number>`coalesce(sum(${scrapeResults.duplicates}), 0)::int`,
 81→      avgDurationMs: sql<number>`coalesce(avg(${scrapeResults.durationMs}), 0)::int`,
 82→    })
 83→    .from(scrapeResults)
 84→    .groupBy(scrapeResults.platform);
 85→
 86→  const [uniqueJobsResult] = await db
 87→    .select({ count: sql<number>`count(*)::int` })
 88→    .from(jobs)
 89→    .where(sql`${jobs.deletedAt} is null`);
 90→
 91→  const totalUniqueJobs = uniqueJobsResult?.count ?? 0;
 92→
 93→  const byPlatform: PlatformStats[] = rows.map((r) => ({
 94→    ...r,
 95→    successRate: r.totalRuns > 0 ? Math.round((r.successCount / r.totalRuns) * 100) : 0,
 96→  }));
 97→
 98→  const totalRuns = byPlatform.reduce((s, p) => s + p.totalRuns, 0);
 99→  const totalSuccess = byPlatform.reduce((s, p) => s + p.successCount, 0);
100→
101→  return {
102→    totalRuns,
103→    totalJobsFound: byPlatform.reduce((s, p) => s + p.totalJobsFound, 0),
104→    totalJobsNew: byPlatform.reduce((s, p) => s + p.totalJobsNew, 0),
105→    totalDuplicates: byPlatform.reduce((s, p) => s + p.totalDuplicates, 0),
106→    totalUniqueJobs,
107→    overallSuccessRate: totalRuns > 0 ? Math.round((totalSuccess / totalRuns) * 100) : 0,
108→    avgDurationMs:
109→      totalRuns > 0
110→        ? Math.round(byPlatform.reduce((s, p) => s + p.avgDurationMs * p.totalRuns, 0) / totalRuns)
111→        : 0,
112→    byPlatform,
113→  };
114→}
