116→export async function getTimeSeriesAnalytics(
117→  opts: GetTimeSeriesOptions = {},
118→): Promise<TimeSeriesPoint[]> {
119→  const now = new Date();
120→  const startDate = opts.startDate ?? new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
121→  const endDate = opts.endDate ?? now;
122→  const groupBy = opts.groupBy ?? "day";
123→  const truncFn = groupBy === "week" ? "week" : "day";
124→
125→  const conditions = [
126→    sql`${scrapeResults.runAt} >= ${startDate}`,
127→    sql`${scrapeResults.runAt} <= ${endDate}`,
128→  ];
129→
130→  if (opts.platform) {
131→    conditions.push(sql`${scrapeResults.platform} = ${opts.platform}`);
132→  }
133→
134→  const rows = await db
135→    .select({
136→      date: sql<string>`date_trunc('${sql.raw(truncFn)}', ${scrapeResults.runAt})::date::text`,
137→      platform: scrapeResults.platform,
138→      jobsFound: sql<number>`coalesce(sum(${scrapeResults.jobsFound}), 0)::int`,
139→      jobsNew: sql<number>`coalesce(sum(${scrapeResults.jobsNew}), 0)::int`,
140→      duplicates: sql<number>`coalesce(sum(${scrapeResults.duplicates}), 0)::int`,
141→      successCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'success')::int`,
142→      failedCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
143→      totalRuns: sql<number>`count(*)::int`,
144→      avgDurationMs: sql<number>`coalesce(avg(${scrapeResults.durationMs}), 0)::int`,
145→    })
146→    .from(scrapeResults)
147→    .where(sql.join(conditions, sql` and `))
148→    .groupBy(
149→      sql`date_trunc('${sql.raw(truncFn)}', ${scrapeResults.runAt})::date`,
150→      scrapeResults.platform,
151→    )
152→    .orderBy(sql`date_trunc('${sql.raw(truncFn)}', ${scrapeResults.runAt})::date`);
153→
154→  return rows;
155→}
