  1→import { publish } from "../lib/event-bus";
  2→import { enrichJobsBatch } from "./ai-enrichment";
  3→import { normalizeAndSaveJobs } from "./normalize";
  4→import { recordScrapeResult } from "./record-scrape-result";
  5→import { scrapeFlextender, scrapeOpdrachtoverheid, scrapeStriive } from "./scrapers/index";
  6→
  7→type ScrapeStatus = "success" | "partial" | "failed";
  8→
  9→async function recordFailure(platform: string, errors: string[], startTime: number): Promise<void> {
 10→  try {
 11→    await recordScrapeResult({
 12→      platform,
 13→      jobsFound: 0,
 14→      jobsNew: 0,
 15→      duplicates: 0,
 16→      durationMs: Date.now() - startTime,
 17→      status: "failed",
 18→      errors,
 19→    });
 20→  } catch (recordErr) {
 21→    console.error(`[scrape-pipeline] recordScrapeResult mislukt voor ${platform}:`, recordErr);
 22→  }
 23→  publish("scrape:error", { platform, errors });
 24→}
 25→
 26→export async function runScrapePipeline(
 27→  platform: string,
 28→  url: string,
 29→): Promise<{ jobsNew: number; duplicates: number; errors: string[] }> {
 30→  const startTime = Date.now();
 31→
 32→  publish("scrape:start", { platform });
 33→
 34→  let listings: Record<string, unknown>[];
 35→  try {
 36→    switch (platform) {
 37→      case "opdrachtoverheid":
 38→        listings = await scrapeOpdrachtoverheid();
 39→        break;
 40→      case "flextender":
 41→        listings = await scrapeFlextender();
 42→        break;
 43→      case "striive":
 44→        listings = await scrapeStriive(url);
 45→        break;
 46→      default:
 47→        return { jobsNew: 0, duplicates: 0, errors: [`Unknown platform: ${platform}`] };
 48→    }
 49→  } catch (err) {
 50→    const errors = [err instanceof Error ? err.message : String(err)];
 51→    await recordFailure(platform, errors, startTime);
 52→    return { jobsNew: 0, duplicates: 0, errors };
 53→  }
 54→
 55→  // Safety net: scraper returned data but nothing parsed — treat as suspicious
 56→  if (listings.length === 0) {
 57→    const errors = [`${platform}: scraper retourneerde 0 listings (mogelijk stille fout)`];
 58→    await recordFailure(platform, errors, startTime);
 59→    return { jobsNew: 0, duplicates: 0, errors };
 60→  }
 61→
 62→  const result = await normalizeAndSaveJobs(platform, listings);
 63→  const durationMs = Date.now() - startTime;
 64→  const status: ScrapeStatus =
 65→    result.errors.length === 0
 66→      ? "success"
 67→      : result.jobsNew > 0 || result.duplicates > 0
 68→        ? "partial"
 69→        : "failed";
 70→
 71→  try {
 72→    await recordScrapeResult({
 73→      platform,
 74→      jobsFound: listings.length,
 75→      jobsNew: result.jobsNew,
 76→      duplicates: result.duplicates,
 77→      durationMs,
 78→      status,
 79→      errors: result.errors,
 80→    });
 81→  } catch (recordErr) {
 82→    console.error(`[scrape-pipeline] recordScrapeResult mislukt voor ${platform}:`, recordErr);
 83→  }
 84→
 85→  publish("scrape:complete", {
 86→    platform,
 87→    jobsFound: listings.length,
 88→    jobsNew: result.jobsNew,
 89→    duplicates: result.duplicates,
 90→    durationMs,
 91→    status,
 92→  });
 93→
 94→  // Fire-and-forget AI enrichment for new jobs
 95→  if (result.jobsNew > 0) {
 96→    enrichJobsBatch({ platform }).catch((err) =>
 97→      console.error(`[AI Enrichment] Failed for ${platform}:`, err),
 98→    );
 99→  }
100→
101→  return result;
102→}
