 10→import type { RawScrapedListing } from "../normalize";
 11→
 12→const MAPPING_FUNCTIONS_AS_STRING = `
 13→function mapBoolean(val) {
 14→  if (typeof val === "boolean") return val;
 15→  if (typeof val === "string") {
 16→    if (val === "YES" || val === "true") return true;
 17→    if (val === "NO" || val === "false") return false;
 18→  }
 19→  return undefined;
 20→}
 21→
 22→function mapWorkArrangement(remote) {
 23→  if (!remote) return undefined;
 24→  switch (remote) {
 25→    case "HYBRID": return "hybride";
 26→    case "NO": return "op_locatie";
 27→    case "YES": return "remote";
 28→    default: return undefined;
 29→  }
 30→}
 31→
 32→function mapBasicListing(job) {
 33→  const loc = job.locationName ?? "";
 34→  const province = loc.includes(" - ") ? loc.split(" - ")[1]?.trim() : undefined;
 35→
 36→  return {
 37→    title: job.title ?? "",
 38→    company: job.client?.name ?? "",
 39→    location: loc || undefined,
 40→    province,
 41→    description: job.description ?? job.shortDescription ?? "",
 42→    externalId: job.referenceCode ?? String(job.id ?? ""),
 43→    externalUrl: \`https://supplier.striive.com/jobrequests/\${job.id ?? ""}\`,
 44→    rateMax: undefined,
 45→    startDate: job.startDate ?? undefined,
 46→    endDate: job.endDate ?? undefined,
 47→    applicationDeadline: job.closingDateOffer ?? undefined,
 48→    postedAt: job.publishedAt ?? undefined,
 49→    contractLabel: job.source ?? undefined,
 50→    positionsAvailable: 1,
 51→  };
 52→}
 53→
 54→function mapDetailListing(job, detail) {
 55→  const base = mapBasicListing(job);
 56→
 57→  const requirements = [];
 58→  if (detail.requirements?.length) {
 59→    for (const r of detail.requirements) {
 60→      const desc = typeof r === "string" ? r : (r.requirement ?? r.description ?? "");
 61→      if (desc) {
 62→        requirements.push({
 63→          description: desc,
 64→          isKnockout: r.type === "KNOCKOUT",
 65→        });
 66→      }
 67→    }
 68→  }
 69→
 70→  const wishes = [];
 71→  if (detail.wishes?.length) {
 72→    for (const w of detail.wishes) {
 73→      const desc = typeof w === "string" ? w : (w.wish ?? w.description ?? "");
 74→      if (desc) {
 75→        wishes.push({ description: desc });
 76→      }
 77→    }
 78→  }
 79→
 80→  const competences = [];
 81→
 82→  const conditions = [];
 83→  if (typeof detail.conditions === "string" && detail.conditions.length > 0) {
 84→    conditions.push(detail.conditions);
 85→  }
 86→
 87→  const detailLocation = detail.location
 88→    ? \`\${detail.location.city ?? ""}\${detail.location.zone ? \` - \${detail.location.zone}\` : ""}\`
 89→    : base.location;
 90→  const detailProvince = detail.location?.zone ?? base.province;
 91→
 92→  return {
 93→    ...base,
 94→    location: detailLocation || base.location,
 95→    province: detailProvince || base.province,
 96→    description:
 97→      detail.description && detail.description.length > (base.description?.length ?? 0)
 98→        ? detail.description
 99→        : base.description,
100→    rateMax:
101→      detail.maxHourlyRate && detail.maxHourlyRate > 0
102→        ? Math.round(detail.maxHourlyRate)
103→        : detail.minHourlyRate && detail.minHourlyRate > 0
104→          ? Math.round(detail.minHourlyRate)
105→          : base.rateMax,
106→    rateMin:
107→      detail.minHourlyRate && detail.minHourlyRate > 0
108→        ? Math.round(detail.minHourlyRate)
109→        : undefined,
110→    workArrangement: mapWorkArrangement(detail.remoteAllowed),
111→    allowsSubcontracting: mapBoolean(detail.onLendingAllowed),
112→    clientReferenceCode: detail.referenceCodeClient || undefined,
113→    contractType: mapContractType(detail.typeOfProfessional),
114→    postedAt: detail.publishedAt ?? base.postedAt,
115→    requirements: requirements.length > 0 ? requirements : [],
116→    wishes: wishes.length > 0 ? wishes : [],
117→    competences,
118→    conditions,
119→    positionsAvailable: detail.positionsCount ?? base.positionsAvailable,
120→
121→    hoursPerWeek: detail.hoursPerWeek ?? undefined,
122→    minHoursPerWeek: detail.minHoursPerWeek ?? undefined,
123→    extensionPossible: detail.extensionPossible ?? undefined,
124→    countryCode: detail.countryCode ?? undefined,
125→    remunerationType: detail.remunerationType ?? undefined,
126→    workExperienceYears: detail.workExperienceYears ?? undefined,
127→    numberOfViews: detail.numberOfViews ?? undefined,
128→    attachments: (detail.attachments ?? []).map((a) => ({
129→      url: a.file?.url ?? "",
130→      description: a.description ?? "",
131→    })),
132→    questions: (detail.questions ?? []).map((q) => ({
133→      question: q.question,
134→      type: q.type,
135→      options: q.options ?? [],
136→    })),
137→    languages: (detail.languages ?? []).map((l) => l.language?.languageCode).filter(Boolean),
138→    descriptionSummary: detail.descriptionSummary ?? undefined,
139→    faqAnswers: (detail.faqAnswerCategories ?? []).flatMap((cat) =>
140→      (cat.faqAnswers ?? []).map((faq) => ({
141→        category: cat.label,
142→        question: faq.question,
143→        answer: faq.answer,
144→      })),
145→    ),
146→    agentContact: detail.agent
147→      ? {
148→          name: detail.agent.name ?? "",
149→          email: detail.agent.email ?? "",
150→          phone: detail.agent.phone ?? "",
151→        }
152→      : undefined,
153→    recruiterContact: detail.recruiter
154→      ? {
155→          name: detail.recruiter.name ?? "",
156→          email: detail.recruiter.email ?? "",
157→          phone: detail.recruiter.phone ?? "",
158→        }
159→      : undefined,
160→  };
161→}
162→
163→function mapContractType(type) {
164→  if (!type) return undefined;
165→  switch (type) {
166→    case "FREELANCER": return "freelance";
167→    case "EMPLOYEES_ONLY": return "vast";
168→    case "INTERIM": return "interim";
169→    case "CONTRACTOR": return "opdracht";
170→    default: return undefined;
171→  }
172→}
173→`;
