175→const STRIIVE_API_LIST = "https://supplier.striive.com/api/v2/job-requests";
176→const STRIIVE_API_DETAIL = "https://supplier.striive.com/api/job-requests";
177→
178→const MODAL_SCRAPE_SCRIPT = `
179→const API_LIST = "${STRIIVE_API_LIST}";
180→const API_DETAIL = "${STRIIVE_API_DETAIL}";
181→
