133→// ========== Auth Config Encryption ==========
134→
135→/** Encrypt een auth config object naar een versleutelde string */
136→export function encryptAuthConfig(config: Record<string, string>): string {
137→  return encrypt(JSON.stringify(config));
138→}
139→
140→/** Decrypt een versleutelde string terug naar auth config object */
141→export function decryptAuthConfig(encoded: string): Record<string, string> {
142→  return JSON.parse(decrypt(encoded));
143→}
144→
145→/**
146→ * Detecteer of een waarde al versleuteld is.
147→ * Encrypted waarden zijn base64 en minimaal 32 bytes (IV + tag).
148→ * Plaintext JSON begint altijd met '{'.
149→ */
150→export function isEncrypted(value: string | null | undefined): boolean {
151→  if (!value || value.length === 0) return false;
152→  // Plaintext JSON begint met '{' of '['
153→  if (value.startsWith("{") || value.startsWith("[")) return false;
154→  // Controleer of het geldige base64 is met minimale lengte (IV + tag = 32 bytes = 44 base64 chars)
155→  if (value.length < 44) return false;
156→  try {
157→    const buf = Buffer.from(value, "base64");
158→    // Re-encode en vergelijk — ongeldige base64 geeft een ander resultaat
159→    return buf.toString("base64") === value;
160→  } catch {
161→    return false;
162→  }
163→}
