  4→import { jobs } from "../db/schema";
  5→import { unifiedJobSchema } from "../schemas/job";
  6→
  7→/** Permissive type for scraped data — Zod validates at runtime via safeParse */
  8→export type RawScrapedListing = Record<string, unknown>;
  9→
 10→export async function normalizeAndSaveJobs(
 11→  platform: string,
 12→  listings: Record<string, unknown>[],
 13→): Promise<{ jobsNew: number; duplicates: number; errors: string[] }> {
 14→  let jobsNew = 0;
 15→  let duplicates = 0;
 16→  const errors: string[] = [];
 17→
 18→  // Stap 1: Valideer alle listings
 19→  const validItems: Array<{
 20→    parsed: z.output<typeof unifiedJobSchema>;
 21→    raw: Record<string, unknown>;
 22→  }> = [];
 23→  for (const raw of listings) {
 24→    const parsed = unifiedJobSchema.safeParse(raw);
 25→    if (!parsed.success) {
 26→      errors.push(`Validation: ${parsed.error.message}`);
 27→    } else {
 28→      validItems.push({ parsed: parsed.data, raw });
 29→    }
 30→  }
 31→
 32→  // Stap 2: Batch upsert
 33→  if (validItems.length > 0) {
 34→    const BATCH_SIZE = 50;
 35→    for (let i = 0; i < validItems.length; i += BATCH_SIZE) {
 36→      const batch = validItems.slice(i, i + BATCH_SIZE);
 37→      try {
 38→        const result = await db
 39→          .insert(jobs)
 40→          .values(
 41→            batch.map((item) => ({
 42→              ...item.parsed,
 43→              platform,
 44→              rawPayload: item.raw,
 45→            })),
 46→          )
 47→          .onConflictDoUpdate({
 48→            target: [jobs.platform, jobs.externalId],
 49→            set: {
 50→              title: sql`excluded.title`,
 51→              company: sql`excluded.company`,
 52→              contractLabel: sql`excluded.contract_label`,
 53→              location: sql`excluded.location`,
 54→              province: sql`excluded.province`,
 55→              description: sql`excluded.description`,
 56→              clientReferenceCode: sql`excluded.client_reference_code`,
 57→              rateMin: sql`excluded.rate_min`,
 58→              rateMax: sql`excluded.rate_max`,
 59→              currency: sql`excluded.currency`,
 60→              positionsAvailable: sql`excluded.positions_available`,
 61→              startDate: sql`excluded.start_date`,
 62→              endDate: sql`excluded.end_date`,
 63→              applicationDeadline: sql`excluded.application_deadline`,
 64→              postedAt: sql`excluded.posted_at`,
 65→              contractType: sql`excluded.contract_type`,
 66→              workArrangement: sql`excluded.work_arrangement`,
 67→              allowsSubcontracting: sql`excluded.allows_subcontracting`,
 68→              requirements: sql`excluded.requirements`,
 69→              wishes: sql`excluded.wishes`,
 70→              competences: sql`excluded.competences`,
 71→              conditions: sql`excluded.conditions`,
 72→              hoursPerWeek: sql`excluded.hours_per_week`,
 73→              minHoursPerWeek: sql`excluded.min_hours_per_week`,
 74→              extensionPossible: sql`excluded.extension_possible`,
 75→              countryCode: sql`excluded.country_code`,
 76→              remunerationType: sql`excluded.remuneration_type`,
 77→              workExperienceYears: sql`excluded.work_experience_years`,
 78→              numberOfViews: sql`excluded.number_of_views`,
 79→              attachments: sql`excluded.attachments`,
 80→              questions: sql`excluded.questions`,
 81→              languages: sql`excluded.languages`,
 82→              descriptionSummary: sql`excluded.description_summary`,
 83→              faqAnswers: sql`excluded.faq_answers`,
 84→              agentContact: sql`excluded.agent_contact`,
 85→              recruiterContact: sql`excluded.recruiter_contact`,
 86→              latitude: sql`excluded.latitude`,
 87→              longitude: sql`excluded.longitude`,
 88→              postcode: sql`excluded.postcode`,
 89→              companyLogoUrl: sql`excluded.company_logo_url`,
 90→              educationLevel: sql`excluded.education_level`,
 91→              durationMonths: sql`excluded.duration_months`,
 92→              sourceUrl: sql`excluded.source_url`,
 93→              sourcePlatform: sql`excluded.source_platform`,
 94→              categories: sql`excluded.categories`,
 95→              companyAddress: sql`excluded.company_address`,
 96→              scrapedAt: sql`now()`,
 97→              deletedAt: sql`null`,
 98→              rawPayload: sql`excluded.raw_payload`,
 99→            },
100→          })
101→          .returning({
102→            id: jobs.id,
103→            isNew: sql<boolean>`xmax = 0`.as("is_new"),
104→          });
105→
106→        const inserted = result.filter((r) => r.isNew).length;
107→        const updated = result.length - inserted;
108→        jobsNew += inserted;
109→        duplicates += updated;
110→      } catch (err) {
111→        errors.push(`DB batch ${i}-${i + batch.length}: ${String(err)}`);
112→      }
113→    }
114→  }
115→
116→  return { jobsNew, duplicates, errors };
