 94→
 95→  const cardRegex =
 96→    /<div\s+class="css-foundjob[^"]*"\s+data-kbslinkurl="([^"]*)"[^>]*>([\s\S]*?)(?=<div\s+class="css-foundjob|<div\s+class="flx-register-panel|$)/gi;
 97→
 98→  let cardMatch = cardRegex.exec(html);
 99→  while (cardMatch !== null) {
100→    const detailPath = cardMatch[1];
101→    const cardHtml = cardMatch[2];
102→
103→    const titleMatch = cardHtml.match(/class="css-jobtitle">([^<]+)/);
104→    const title = titleMatch?.[1]?.trim();
105→    if (!title) continue;
106→
107→    const companyMatch = cardHtml.match(/class="css-customer">([^<]+)/);
108→    const company = companyMatch?.[1]?.trim();
109→
110→    // Extract aanvraagnr from URL params or path
111→    const aanvraagMatch = detailPath.match(/aanvraagnr=(\d+)/) ?? detailPath.match(/\/(\d+)$/);
112→    const externalId = aanvraagMatch?.[1] || `flx-${listings.length}`;
113→    if (!externalId) continue;
114→
115→    // Build proper external URL from original detail path
116→    const externalUrl = detailPath.startsWith("http")
117→      ? detailPath
118→      : `https://www.flextender.nl${detailPath.startsWith("/") ? "" : "/"}${detailPath}`;
119→
120→    const fields = parseFieldPairs(cardHtml);
121→
122→    const province = extractProvince(fields.Regio);
123→    const location = fields.Regio ?? undefined;
124→
125→    // Parse "Uren per week": "36 uur" → 36, "24 tot 32 uur" → min=24, max=32
126→    const { hoursPerWeek, minHoursPerWeek } = parseHoursPerWeek(fields["Uren per week"]);
127→
128→    // Extract company logo URL
129→    const logoMatch =
130→      cardHtml.match(/class="flx-client-logo"[^>]*src="([^"]+)"/i) ??
131→      cardHtml.match(/src="([^"]+)"[^>]*class="flx-client-logo"/i);
132→    const companyLogoUrl = logoMatch?.[1] ?? undefined;
133→
134→    // Opleidingsniveau from listing card
135→    const educationLevel = fields.Opleidingsniveau ?? undefined;
136→
137→    // Duration from "Duur" field: "6 maanden" → 6
138→    const durationMonths = parseDurationMonths(fields.Duur);
139→
140→    listings.push({
141→      title,
142→      company,
143→      location,
144→      province,
145→      description: `${title} — ${company ?? "Flextender"} opdracht`,
146→      externalId,
147→      externalUrl,
148→      startDate: parseDutchDate(fields.Start),
149→      applicationDeadline: parseDutchDate(fields["Einde inschrijfdatum"]),
