151→      countryCode: "NL",
152→      hoursPerWeek,
153→      minHoursPerWeek,
154→      companyLogoUrl,
155→      educationLevel,
156→      durationMonths,
157→      _rawHours: fields["Uren per week"] ?? undefined, // kept for conditions fallback
158→    });
159→    cardMatch = cardRegex.exec(html);
160→  }
161→
162→  return listings;
