167→/** Verrijk listings met content van hun detail-pagina's (parallel, max 5 tegelijk) */
168→async function enrichListings(
169→  listings: FlextenderListing[],
170→  logger?: { info: (m: string) => void; warn: (m: string) => void },
171→): Promise<RawScrapedListing[]> {
172→  const CONCURRENCY = 5;
173→  const results: RawScrapedListing[] = [];
174→  let detailFailures = 0;
175→
176→  for (let i = 0; i < listings.length; i += CONCURRENCY) {
177→    const batch = listings.slice(i, i + CONCURRENCY);
178→    const enrichedBatch = await Promise.all(
179→      batch.map(async (listing) => {
180→        try {
181→          const detail = await fetchDetailPage(listing.externalId);
182→          if (
183→            listing._rawHours &&
184→            !detail.conditions?.some((condition) => condition.includes("Uren per week"))
185→          ) {
186→            detail.conditions = [
187→              ...(detail.conditions ?? []),
188→              `Uren per week: ${listing._rawHours}`,
189→            ];
190→          }
191→          const { _rawHours, ...listingClean } = listing;
192→          return { ...listingClean, ...detail };
193→        } catch (err) {
194→          detailFailures++;
195→          (logger?.warn ?? console.warn)(
196→            `Detail ophalen mislukt voor ${listing.externalId}: ${err}`,
197→          );
198→          // Return listing without detail enrichment — still usable
199→          const { _rawHours, ...listingClean } = listing;
200→          return listingClean;
201→        }
202→      }),
203→    );
204→    results.push(...enrichedBatch);
205→
206→    // Back-off between batches to avoid overwhelming Flextender
207→    if (i + CONCURRENCY < listings.length) {
208→      await new Promise((r) => setTimeout(r, 500));
209→    }
210→  }
211→
212→  if (detailFailures > 0) {
213→    const log = logger?.warn ?? console.warn;
214→    log(
215→      `Flextender: ${detailFailures}/${listings.length} detail-pagina's mislukt (${Math.round((1 - detailFailures / listings.length) * 100)}% verrijkt)`,
216→    );
217→  }
218→
219→  return results;
220→}
