222→/** Haal detail-pagina op en parse gestructureerde secties */
223→async function fetchDetailPage(aanvraagnr: string): Promise<FlextenderDetail> {
224→  const url = `${DETAIL_BASE}${aanvraagnr}`;
225→  const res = await fetch(url, { signal: AbortSignal.timeout(10_000) });
226→  if (!res.ok) throw new Error(`Detail ${res.status}: ${res.statusText}`);
227→
228→  const html = await res.text();
229→  return parseDetailHtml(html);
230→}
