232→/** Parse detail-pagina HTML naar gestructureerde velden */
233→function parseDetailHtml(html: string): FlextenderDetail {
234→  const result: FlextenderDetail = {};
235→
236→  const descMatch = html.match(
237→    /class="css-formattedjobdescription">([\s\S]*?)(?:<\/div>\s*<div\s+(?:style|class="css-navigation))/,
238→  );
239→  if (!descMatch) return result;
240→
241→  const content = descMatch[1];
242→
243→  const sections = extractSections(content);
244→
245→  const findSection = (needle: string): string | undefined => {
246→    const key = Object.keys(sections).find((k) => k.toLowerCase().includes(needle.toLowerCase()));
247→    return key ? sections[key] : undefined;
248→  };
249→
250→  const descParts: string[] = [];
251→  for (const key of ["Opdracht", "Organisatietekst", "Opdrachtgever"]) {
252→    if (sections[key]) descParts.push(sections[key]);
253→  }
254→  if (descParts.length > 0) {
255→    result.description = decodeEntities(descParts.join("\n\n")).substring(0, 8000);
256→  }
257→
258→  const reqText = findSection("vereisten") ?? findSection("knock-out");
259→  if (reqText) {
260→    result.requirements = parseNumberedList(reqText).map((item) => ({
261→      description: item,
262→      isKnockout: true,
263→    }));
264→  }
265→
266→  const selText = findSection("selectiecriteria");
267→  if (selText) {
268→    result.wishes = parseNumberedList(selText).map((item) => ({
269→      description: item,
270→    }));
271→  }
272→
273→  const compText = findSection("competenties");
274→  if (compText) {
275→    result.competences = parseBulletList(compText);
276→  }
277→
278→  const conditions: string[] = [];
279→
280→  const funcText = findSection("functieschaal");
281→  if (funcText) {
282→    const scaleMatch = funcText.match(/schaal\s*(\d+)/i);
283→    if (scaleMatch) conditions.push(`Functieschaal ${scaleMatch[1]}`);
284→  }
285→
286→  const feeText = findSection("fee");
287→  if (feeText) conditions.push(`Fee: ${feeText.trim()}`);
288→
289→  const werkText = findSection("werkdagen");
290→  if (werkText) conditions.push(`Werkdagen: ${werkText.trim()}`);
291→
292→  const cvText = findSection("cv-eisen");
293→  if (cvText) conditions.push(`CV-eisen: ${cvText.trim()}`);
294→
295→  // === Extract workArrangement from Werkdagen section ===
296→  if (werkText) {
297→    const lower = werkText.toLowerCase();
298→    if (
299→      lower.includes("hybride") ||
300→      lower.includes("in overleg") ||
301→      lower.includes("onderlinge afstemming")
302→    ) {
303→      result.workArrangement = "hybride";
304→    } else if (lower.includes("remote") || lower.includes("thuiswerk")) {
305→      result.workArrangement = "remote";
306→    } else {
307→      result.workArrangement = "op_locatie";
308→    }
309→  }
310→
311→  // === Extract positionsAvailable from "Benodigd aantal professionals" ===
312→  const profText = findSection("benodigd aantal");
313→  if (profText) {
314→    const numMatch = profText.match(/(\d+)/);
315→    if (numMatch) result.positionsAvailable = parseInt(numMatch[1], 10);
316→  }
317→
318→  // === Parse summary fields for structured data + conditions ===
319→  const summaryHtml =
320→    extractBetween(
321→      html,
322→      'class="css-summarybackground">',
323→      'class="css-formattedjobdescription">',
324→    ) ?? "";
325→  const summaryFields = parseFieldPairs(summaryHtml);
326→
327→  // extensionPossible from "Opties verlenging"
328→  const extensionRaw = summaryFields["Opties verlenging"];
329→  if (extensionRaw) {
330→    const lower = extensionRaw.toLowerCase();
331→    if (lower.includes("niet") || lower === "nee" || lower === "geen") {
332→      result.extensionPossible = false;
333→    } else {
334→      result.extensionPossible = true;
335→    }
336→  }
337→
338→  // hoursPerWeek from summary (may override listing-level if detail has it)
339→  const summaryHours = parseHoursPerWeek(summaryFields["Uren per week"]);
340→  if (summaryHours.hoursPerWeek) {
341→    result.hoursPerWeek = summaryHours.hoursPerWeek;
342→    if (summaryHours.minHoursPerWeek) result.minHoursPerWeek = summaryHours.minHoursPerWeek;
343→  }
344→
345→  // educationLevel from summary "Opleidingsniveau"
346→  if (summaryFields.Opleidingsniveau) {
347→    result.educationLevel = summaryFields.Opleidingsniveau;
348→  }
349→
350→  // durationMonths from summary "Duur"
351→  if (summaryFields.Duur) {
352→    const dm = parseDurationMonths(summaryFields.Duur);
353→    if (dm) result.durationMonths = dm;
354→  }
355→
356→  // Remaining summary fields → conditions (keep existing behavior)
357→  const skipKeys = new Set([
358→    "Start",
359→    "Regio",
360→    "Einde inschrijfdatum",
361→    "Uren per week",
362→    "Opties verlenging",
363→    "Opleidingsniveau",
364→    "Duur",
365→  ]);
366→  for (const [key, value] of Object.entries(summaryFields)) {
367→    if (!value || skipKeys.has(key)) continue;
368→    conditions.push(`${key}: ${value}`);
369→  }
370→
371→  if (conditions.length > 0) {
372→    result.conditions = conditions.map(decodeEntities);
373→  }
374→
375→  // Always set countryCode for Flextender (Dutch government platform)
376→  result.countryCode = "NL";
377→
378→  return result;
379→}
