381→/** Extract text between two markers in HTML */
382→function extractBetween(html: string, start: string, end: string): string | null {
383→  const startIdx = html.indexOf(start);
384→  if (startIdx === -1) return null;
385→  const endIdx = html.indexOf(end, startIdx + start.length);
386→  if (endIdx === -1) return null;
387→  return html.substring(startIdx + start.length, endIdx);
388→}
389→
390→/** Splits HTML content op <strong> secties, retourneert header→body map */
391→function extractSections(html: string): Record<string, string> {
392→  const sections: Record<string, string> = {};
393→  const parts = html.split(/<(?:strong|b)>/i);
394→
395→  for (let i = 1; i < parts.length; i++) {
396→    const closeIdx = parts[i].search(/<\/(?:strong|b)>/i);
397→    if (closeIdx === -1) continue;
398→
399→    const header = stripHtml(parts[i].substring(0, closeIdx)).trim();
400→    const body = stripHtml(parts[i].substring(closeIdx)).trim();
401→
402→    if (header && body && header.length < 100) {
403→      sections[header] = body;
404→    }
405→  }
406→  return sections;
407→}
