409→/** Parse genummerde lijst (1. item; 2. item) naar string array */
410→function parseNumberedList(text: string): string[] {
411→  const items = text.split(/\n/).filter((l) => l.trim());
412→  const result: string[] = [];
413→  for (const line of items) {
414→    const cleaned = line.replace(/^\d+[.)]\s*/, "").trim();
415→    if (cleaned.length > 5) result.push(cleaned);
416→  }
417→  if (result.length === 0) {
418→    return text
419→      .split(/[;\n]/)
420→      .map((s) => s.replace(/^\d+[.)]\s*/, "").trim())
421→      .filter((s) => s.length > 5);
422→  }
423→  return result;
424→}
425→
426→/** Parse bullet list (- item; - item) naar string array */
427→function parseBulletList(text: string): string[] {
428→  return text
429→    .split(/[;\n]/)
430→    .map((s) => s.replace(/^[-•–]\s*/, "").trim())
431→    .filter((s) => s.length > 2);
432→}
