434→/** Decode common HTML entities in a string */
435→function decodeEntities(s: string): string {
436→  return s
437→    .replace(/&euro;/gi, "€")
438→    .replace(/&rsquo;/gi, "\u2019")
439→    .replace(/&lsquo;/gi, "\u2018")
440→    .replace(/&rdquo;/gi, "\u201D")
441→    .replace(/&ldquo;/gi, "\u201C")
442→    .replace(/&eacute;/gi, "é")
443→    .replace(/&euml;/gi, "ë")
444→    .replace(/&uuml;/gi, "ü")
445→    .replace(/&iuml;/gi, "ï")
446→    .replace(/&ouml;/gi, "ö")
447→    .replace(/&auml;/gi, "ä")
448→    .replace(/&nbsp;/gi, " ")
449→    .replace(/&amp;/gi, "&")
450→    .replace(/&lt;/gi, "<")
451→    .replace(/&gt;/gi, ">")
452→    .replace(/&quot;/gi, '"')
453→    .replace(/&#39;/gi, "'")
454→    .replace(/&#\d+;/g, (m) => String.fromCharCode(Number(m.slice(2, -1))));
455→}
