457→/** Parse alle caption-value paren uit een card HTML */
458→function parseFieldPairs(cardHtml: string): Record<string, string> {
459→  const fields: Record<string, string> = {};
460→  const pairRegex = /class="css-caption">([^<]+)<[\s\S]*?class="css-value">([^<]+)</gi;
461→  let pairMatch = pairRegex.exec(cardHtml);
462→  while (pairMatch !== null) {
463→    const key = pairMatch[1].trim();
464→    const value = pairMatch[2].trim();
465→    if (!fields[key]) fields[key] = value;
466→    pairMatch = pairRegex.exec(cardHtml);
467→  }
468→  return fields;
469→}
