471→/** Parse Nederlandse datum (bijv. "16 maart 2026") naar Date of undefined */
472→function parseDutchDate(raw: string | undefined): Date | undefined {
473→  if (!raw) return undefined;
474→  const s = raw.trim();
475→  if (s === "Z.s.m." || s.includes("uur") || s.length < 6) return undefined;
476→
477→  const months: Record<string, string> = {
478→    januari: "01",
479→    februari: "02",
480→    maart: "03",
481→    april: "04",
482→    mei: "05",
483→    juni: "06",
484→    juli: "07",
485→    augustus: "08",
486→    september: "09",
487→    oktober: "10",
488→    november: "11",
489→    december: "12",
490→  };
491→
492→  const match = s.match(/^(\d{1,2})\s+(\w+)\s+(\d{4})$/);
493→  if (match) {
494→    const month = months[match[2].toLowerCase()];
495→    if (month) {
496→      return new Date(`${match[3]}-${month}-${match[1].padStart(2, "0")}`);
497→    }
498→  }
499→
500→  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return new Date(s.slice(0, 10));
501→
502→  return undefined;
503→}
504→
505→/** Parse Dutch duration "6 maanden" → 6, "12 weken" → 3, "1 jaar" → 12 */
506→function parseDurationMonths(raw: string | undefined): number | undefined {
507→  if (!raw) return undefined;
508→  const lower = raw.toLowerCase().trim();
509→
510→  const maandenMatch = lower.match(/(\d+)\s*maand/);
511→  if (maandenMatch) return parseInt(maandenMatch[1], 10);
512→
513→  const wekenMatch = lower.match(/(\d+)\s*we[ek]/);
514→  if (wekenMatch) return Math.round(parseInt(wekenMatch[1], 10) / 4.33);
515→
516→  const jaarMatch = lower.match(/(\d+)\s*jaar/);
517→  if (jaarMatch) return parseInt(jaarMatch[1], 10) * 12;
518→
519→  return undefined;
520→}
521→
522→/** Parse "Uren per week" field: "36 uur" → {max:36}, "24 tot 32 uur" → {min:24, max:32} */
523→function parseHoursPerWeek(raw: string | undefined): {
524→  hoursPerWeek?: number;
525→  minHoursPerWeek?: number;
526→} {
527→  if (!raw) return {};
528→  const rangeMatch = raw.match(/(\d+)\s*tot\s*(\d+)/);
529→  if (rangeMatch) {
530→    return {
531→      minHoursPerWeek: parseInt(rangeMatch[1], 10),
532→      hoursPerWeek: parseInt(rangeMatch[2], 10),
533→    };
534→  }
535→  const singleMatch = raw.match(/(\d+)/);
536→  if (singleMatch) {
537→    return { hoursPerWeek: parseInt(singleMatch[1], 10) };
538→  }
539→  return {};
540→}
