542→/** Map regio/locatie naar Nederlandse provincie */
543→function extractProvince(location: string | undefined): string | undefined {
544→  if (!location) return undefined;
545→  const loc = location.toLowerCase();
546→
547→  const provinces: Record<string, string> = {
548→    "noord-holland": "Noord-Holland",
549→    "zuid-holland": "Zuid-Holland",
550→    "noord-brabant": "Noord-Brabant",
551→    utrecht: "Utrecht",
552→    gelderland: "Gelderland",
553→    overijssel: "Overijssel",
554→    limburg: "Limburg",
555→    friesland: "Friesland",
556→    groningen: "Groningen",
557→    drenthe: "Drenthe",
558→    flevoland: "Flevoland",
559→    zeeland: "Zeeland",
560→  };
561→
562→  for (const [key, value] of Object.entries(provinces)) {
563→    if (loc.includes(key)) return value;
564→  }
565→  return undefined;
566→}
