 80→export async function scrapeOpdrachtoverheid(): Promise<RawScrapedListing[]> {
 81→  console.log("Opdrachtoverheid scrapen via API");
 82→
 83→  const MAX_RETRIES = 2;
 84→  let attempt = 0;
 85→
 86→  while (attempt <= MAX_RETRIES) {
 87→    try {
 88→      const res = await fetch(`${API_BASE}/search`, {
 89→        method: "POST",
 90→        headers: {
 91→          "Content-Type": "application/json",
 92→          "User-Agent": "Mozilla/5.0 (compatible; MotianBot/1.0)",
 93→        },
 94→        body: JSON.stringify({
 95→          single: false,
 96→          limit: MAX_RESULTS,
 97→          offset: 0,
 98→          disjunction: 0,
 99→          user_coordinates: {},
100→          filters: {
101→            and_filters: [
102→              {
103→                filters: [
104→                  {
105→                    field_name: "tender_active",
106→                    operator: "eq",
107→                    value: true,
108→                  },
109→                ],
110→              },
111→            ],
112→          },
113→        }),
114→      });
115→
116→      if (!res.ok) {
117→        const errorBody = await res.text().catch(() => "");
118→        throw new Error(`API ${res.status}: ${res.statusText} — ${errorBody.slice(0, 500)}`);
119→      }
120→
121→      const data = (await res.json()) as OpdrachtoverheidApiResponse;
122→      const allTenders = data.negometrix_tenders ?? [];
123→
124→      console.log(`Opdrachtoverheid API: ${allTenders.length} actieve opdrachten`);
125→
126→      const listings: RawScrapedListing[] = allTenders.map((t) => {
127→        const loc = t.vacancies_location ?? {};
128→        const empType = (t.contract_type ?? "").toLowerCase();
129→
130→        const contractType =
131→          empType.includes("freelance") || empType === "temporary"
132→            ? "freelance"
133→            : empType.includes("detachering") || empType.includes("loondienst")
134→              ? "interim"
135→              : undefined;
136→
137→        const allowsSubcontracting =
138→          empType.includes("freelance") || empType === "temporary" ? true : undefined;
139→
140→        const requirements = parseHtmlList(t.tender_requirements);
141→        const competences = parseHtmlList(t.tender_competences);
142→
143→        // === Rate logic: tariff = indicative, maximum_tariff = ceiling ===
144→        const rawMaxTariff = t.tender_maximum_tariff ?? 0;
145→        const maxTariff = rawMaxTariff > 0 ? Math.round(rawMaxTariff) : undefined;
146→        const rawBaseTariff = t.tender_tariff ? parseFloat(String(t.tender_tariff)) : 0;
147→        const baseTariff = rawBaseTariff > 0 ? Math.round(rawBaseTariff) : undefined;
148→        const rateMax = maxTariff ?? baseTariff;
149→        const rateMin = maxTariff && baseTariff && baseTariff < maxTariff ? baseTariff : undefined;
150→
151→        // === Hours: tender_hours_week (100%), with optional min/max range ===
152→        const rawMaxHours = t.tender_max_hours ?? 0;
153→        const rawHoursWeek = t.tender_hours_week ?? 0;
154→        const hoursPerWeek =
155→          rawMaxHours > 0
156→            ? Math.round(rawMaxHours)
157→            : rawHoursWeek > 0
158→              ? Math.round(rawHoursWeek)
159→              : undefined;
160→        const rawMinHours = t.tender_min_hours ?? 0;
161→        const minHoursPerWeek =
162→          rawMinHours > 0 && rawMinHours < (hoursPerWeek ?? Number.POSITIVE_INFINITY)
163→            ? Math.round(rawMinHours)
164→            : undefined;
165→
166→        // === Extension from tender_other_information ===
167→        const otherInfo = stripHtml(t.tender_other_information);
168→        let extensionPossible: boolean | undefined;
169→        if (otherInfo) {
170→          const lower = otherInfo.toLowerCase();
171→          if (lower.includes("verleng")) {
172→            extensionPossible =
173→              !lower.includes("geen verlenging") && !lower.includes("niet verleng");
174→          }
175→        }
176→
177→        // === Work arrangement from tender_hybrid_working ===
178→        const workArrangement = t.tender_hybrid_working === true ? ("hybride" as const) : undefined;
179→
180→        // === Attachments from tender_document ===
181→        const attachments: Array<{ url: string; description: string }> = [];
182→        if (t.tender_document) {
183→          attachments.push({ url: t.tender_document, description: t.tender_document });
184→        }
185→
186→        return {
187→          title: t.tender_name || t.tender_buying_organization,
188→          company: t.tender_buying_organization,
189→          location: loc.city
190→            ? `${loc.city}${loc.province ? ` - ${loc.province}` : ""}`
191→            : (loc.province ?? undefined),
192→          province: loc.province ?? undefined,
193→          description: ensureMinLength(
194→            stripHtml(t.tender_description_html) ||
195→              stripHtml(t.tender_overview) ||
196→              t.tender_description ||
197→              [stripHtml(t.tender_team), stripHtml(t.tender_interview), otherInfo]
198→                .filter(Boolean)
199→                .join("\n\n") ||
200→              t.tender_name ||
201→              "Geen beschrijving beschikbaar voor deze opdracht",
202→          ),
203→          externalId: t.web_key || t.tender_id?.toString() || "",
204→          externalUrl: t.opdracht_overheid_url || `https://www.opdrachtoverheid.nl/`,
205→          rateMax,
206→          rateMin,
207→          startDate: validDate(t.tender_start_date),
208→          endDate: validDate(t.tender_end_date),
209→          applicationDeadline: validDate(t.tender_date) ?? validDate(t.tender_end_date),
210→          postedAt: validDate(t.tender_first_seen),
211→          contractType,
212→          allowsSubcontracting,
213→          workArrangement,
214→          contractLabel: t.tender_category != null ? CATEGORY_MAP[t.tender_category] : undefined,
215→          positionsAvailable: parseInt(String(t.tender_number_of_professionals ?? 1), 10) || 1,
216→          requirements:
217→            requirements.length > 0
218→              ? requirements.map((r) => ({ description: r, isKnockout: true }))
219→              : [],
220→          competences: competences.length > 0 ? competences : [],
221→
222→          // === Verrijkte Data (new columns) ===
223→          hoursPerWeek,
224→          minHoursPerWeek,
225→          extensionPossible,
226→          countryCode: "NL",
227→          attachments,
228→
229→          // === Locatie & Organisatie ===
230→          latitude: loc.latitude ? parseFloat(loc.latitude) : undefined,
231→          longitude: loc.longitude ? parseFloat(loc.longitude) : undefined,
232→          postcode: loc.postcode ?? undefined,
233→          companyLogoUrl: loc.avatar
234→            ? `https://kbenp-match-api.azurewebsites.net/images/${loc.avatar}`
235→            : undefined,
236→
237→          // === Opdracht Kenmerken ===
238→          sourceUrl: t.tender_url ?? undefined,
239→          sourcePlatform: t.tender_source ?? undefined,
240→          durationMonths: computeDurationMonths(t.tender_start_date, t.tender_end_date),
241→          categories: (t.tender_categories ?? [])
242→            .map((category) => category.tender_category_obj?.type)
243→            .filter(Boolean),
244→          companyAddress: loc.company_address ?? undefined,
245→        };
246→      });
247→
248→      const validListings = listings.filter(
249→        (listing) => (listing.externalId as string)?.length > 0,
250→      );
251→
252→      console.log(`Opdrachtoverheid: ${validListings.length} geldige opdrachten`);
253→
254→      return validListings;
255→    } catch (err) {
256→      attempt++;
257→      if (attempt > MAX_RETRIES) {
258→        throw new Error(
259→          `Opdrachtoverheid scrape mislukt na ${MAX_RETRIES + 1} pogingen: ${err instanceof Error ? err.message : String(err)}`,
260→        );
261→      } else {
262→        const delay = 1200 * 2 ** attempt + Math.floor(Math.random() * 500);
263→        console.warn(`Opdrachtoverheid poging ${attempt} mislukt, retry in ${delay}ms: ${err}`);
264→        await new Promise((r) => setTimeout(r, delay));
265→      }
266→    }
267→  }
268→
269→  // Unreachable — while loop always returns or throws — but satisfies TypeScript
270→  throw new Error("Opdrachtoverheid scrape: onverwacht einde van retry-loop");
271→}
272→
273→/** Compute duration in months from start/end date strings */
274→function computeDurationMonths(
275→  start: string | null | undefined,
276→  end: string | null | undefined,
277→): number | undefined {
278→  if (!start || !end) return undefined;
279→  const s = new Date(start);
280→  const e = new Date(end);
281→  if (Number.isNaN(s.getTime()) || Number.isNaN(e.getTime())) return undefined;
282→  if (s.getFullYear() < 2020 || e.getFullYear() < 2020) return undefined;
283→  const months = (e.getFullYear() - s.getFullYear()) * 12 + (e.getMonth() - s.getMonth());
284→  return months > 0 ? months : undefined;
285→}
286→
287→/** Filter out API sentinel dates (pre-2020) that mean "unknown/TBD" */
288→function validDate(raw: string | null | undefined): string | undefined {
289→  if (!raw) return undefined;
290→  const year = parseInt(raw.slice(0, 4), 10);
291→  if (Number.isNaN(year) || year < 2020) return undefined;
292→  return raw;
293→}
294→
295→/** Zorg dat beschrijving minimaal 10 tekens is (schema eis) */
296→function ensureMinLength(text: string): string {
297→  if (text.length >= 10) return text;
298→  return `${text} — opdracht via Opdrachtoverheid`;
299→}
300→
301→/** Parse HTML <li> items naar string array */
302→function parseHtmlList(html: string | null | undefined): string[] {
303→  if (!html) return [];
304→  const items: string[] = [];
305→  const liRegex = /<li[^>]*>([\s\S]*?)<\/li>/gi;
306→  let match = liRegex.exec(html);
307→  while (match !== null) {
308→    const text = stripHtml(match[1]).trim();
309→    if (text.length > 0) items.push(text);
310→    match = liRegex.exec(html);
311→  }
312→  if (items.length === 0) {
313→    const plain = stripHtml(html);
314→    if (plain.length > 0) {
315→      items.push(
316→        ...plain
317→          .split("\n")
318→          .map((s) => s.trim())
319→          .filter((s) => s.length > 0),
320→      );
321→    }
322→  }
323→  return items;
324→}
