import { revalidatePath } from "next/cache";
import type { NextRequest } from "next/server";
import { uploadFile } from "@/src/lib/file-storage";
import { autoMatchCandidateToJobs } from "@/src/services/auto-matching";
import {
  createCandidate,
  enrichCandidateFromCV,
  findDuplicateCandidate,
} from "@/src/services/candidates";
import { parseCV } from "@/src/services/cv-parser";

export const dynamic = "force-dynamic";
export const maxDuration = 60;

const ALLOWED_TYPES = [
  "application/pdf",
  "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
] as const;

type AllowedMimeType = (typeof ALLOWED_TYPES)[number];

const MAX_SIZE_MB = 20;

/** Heuristic CV quality score (0–100) en label voor de grade-stap. */
function computeGradeFromParsed(parsed: {
  skills?: { hard?: { name: string }[]; soft?: { name: string }[] };
  experience?: unknown[];
  education?: unknown[];
}): { score: number; label: string } {
  const skillCount = (parsed.skills?.hard?.length ?? 0) + (parsed.skills?.soft?.length ?? 0);
  const expCount = Array.isArray(parsed.experience) ? parsed.experience.length : 0;
  const eduCount = Array.isArray(parsed.education) ? parsed.education.length : 0;
  let score = Math.min(
    100,
    20 + skillCount * 3 + Math.min(expCount, 5) * 8 + Math.min(eduCount, 3) * 5,
  );
  score = Math.round(Math.max(0, score));
  if (score >= 80) return { score, label: "Sterk profiel" };
  if (score >= 60) return { score, label: "Goed profiel" };
  if (score >= 40) return { score, label: "Basis profiel" };
  return { score, label: "Beperkt profiel" };
}

function sseEvent(data: Record<string, unknown>): Uint8Array {
  return new TextEncoder().encode(`data: ${JSON.stringify(data)}\n\n`);
}

export async function POST(request: NextRequest) {
  // Pre-validate before starting the stream (these return JSON errors)
  if (!process.env.BLOB_READ_WRITE_TOKEN) {
    console.error("[CV Analyse] BLOB_READ_WRITE_TOKEN is not configured");
    return Response.json(
      { error: "Bestandsopslag is niet geconfigureerd. Stel BLOB_READ_WRITE_TOKEN in." },
      { status: 503 },
    );
  }

  const formData = await request.formData();
  const file = formData.get("cv") as File | null;

  if (!file) {
    return Response.json({ error: "Geen bestand ontvangen" }, { status: 400 });
  }

  const mimeType = file.type;
  if (!ALLOWED_TYPES.includes(mimeType as AllowedMimeType)) {
    return Response.json(
      { error: "Ongeldig bestandstype. Alleen PDF en Word (.docx) zijn toegestaan." },
      { status: 400 },
    );
  }

  if (file.size > MAX_SIZE_MB * 1024 * 1024) {
    return Response.json(
      { error: `Bestand te groot. Maximaal ${MAX_SIZE_MB}MB toegestaan.` },
      { status: 400 },
    );
  }

  const buffer = Buffer.from(await file.arrayBuffer());

  const stream = new ReadableStream({
    async start(controller) {
      try {
        // Step 1: Upload
        controller.enqueue(
          sseEvent({ step: "upload", status: "active", label: "CV uploaden naar opslag..." }),
        );
        const { url: fileUrl } = await uploadFile(
          buffer,
          `cv/${Date.now()}-${file.name}`,
          mimeType,
        );
        controller.enqueue(sseEvent({ step: "upload", status: "complete", label: "CV geüpload" }));

        // Step 2: Parse
        controller.enqueue(
          sseEvent({ step: "parse", status: "active", label: "CV analyseren met AI..." }),
        );
        const parsed = await parseCV(buffer, mimeType as AllowedMimeType);
        controller.enqueue(
          sseEvent({
            step: "parse",
            status: "complete",
            label: `CV geanalyseerd`,
            detail: `${parsed.name}${parsed.role ? ` — ${parsed.role}` : ""}`,
          }),
        );

        // Step 2: Grade (expliciete beoordelingsfase op basis van parsed CV)
        controller.enqueue(
          sseEvent({ step: "grade", status: "active", label: "CV beoordelen..." }),
        );
        const gradeScore = computeGradeFromParsed(parsed);
        controller.enqueue(
          sseEvent({
            step: "grade",
            status: "complete",
            label: "CV beoordeeld",
            detail: `${gradeScore.score}/100 — ${gradeScore.label}`,
            gradeScore: gradeScore.score,
            gradeLabel: gradeScore.label,
          }),
        );

        // Step 3: Deduplicate
        controller.enqueue(
          sseEvent({ step: "deduplicate", status: "active", label: "Kandidaat controleren..." }),
        );
        const duplicates = await findDuplicateCandidate(parsed);

        let candidate: { id: string; name: string } | null | undefined;
        if (duplicates.exact) {
          candidate = await enrichCandidateFromCV(
            duplicates.exact.id,
            parsed,
            JSON.stringify(parsed),
            fileUrl,
          );
          if (!candidate) {
            controller.enqueue(
              sseEvent({
                step: "deduplicate",
                status: "error",
                label: "Bestaande kandidaat kon niet worden verrijkt",
              }),
            );
            controller.close();
            return;
          }
          controller.enqueue(
            sseEvent({
              step: "deduplicate",
              status: "complete",
              label: "Bestaande kandidaat gevonden",
              detail: candidate.name,
            }),
          );
        } else {
          candidate = await createCandidate({
            name: parsed.name,
            email: parsed.email ?? undefined,
            phone: parsed.phone ?? undefined,
            role: parsed.role,
            skills: [
              ...parsed.skills.hard.map((s) => s.name),
              ...parsed.skills.soft.map((s) => s.name),
            ],
            location: parsed.location ?? undefined,
            notes: parsed.introduction,
            source: "cv-analyse",
          });
          await enrichCandidateFromCV(candidate.id, parsed, JSON.stringify(parsed), fileUrl);
          controller.enqueue(
            sseEvent({
              step: "deduplicate",
              status: "complete",
              label: "Nieuwe kandidaat aangemaakt",
              detail: candidate.name,
            }),
          );
        }

        // Step 4: Match
        controller.enqueue(
          sseEvent({ step: "match", status: "active", label: "Matchen met vacatures..." }),
        );
        let matches: Awaited<ReturnType<typeof autoMatchCandidateToJobs>> = [];
        try {
          matches = await autoMatchCandidateToJobs(candidate.id);
        } catch (err) {
          console.error("[CV Analyse] Auto-matching mislukt:", err);
        }
        controller.enqueue(
          sseEvent({
            step: "match",
            status: "complete",
            label: `${matches.length} vacature${matches.length === 1 ? "" : "s"} gematcht`,
          }),
        );

        console.log(`[CV Analyse] Done: ${matches.length} matches for candidate ${candidate.id}`);

        // Final event: full result
        controller.enqueue(
          sseEvent({
            step: "done",
            result: {
              candidate,
              matches,
              fileUrl,
              parsed,
              isExistingCandidate: !!duplicates.exact,
            },
          }),
        );

        revalidatePath("/professionals");
      } catch (err) {
        const message = err instanceof Error ? err.message : "Onbekende fout";
        console.error("[CV Analyse] Error:", message, err);
        controller.enqueue(sseEvent({ step: "error", label: `CV analyse mislukt: ${message}` }));
      } finally {
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}

import { Output } from "ai";
import mammoth from "mammoth";
import { geminiFlash, tracedGenerateText as generateText } from "../lib/ai-models";
import { withRetry } from "../lib/retry";
import { type ParsedCV, parsedCVSchema } from "../schemas/candidate-intelligence";

const SYSTEM_PROMPT = `Je bent een CV-parser voor een Nederlands recruitment platform. Analyseer dit CV en extraheer ALLE relevante informatie zo volledig mogelijk.

PERSOONLIJKE GEGEVENS:
- Naam, email, telefoon, geboortedatum (YYYY-MM-DD), nationaliteit, woonplaats
- Als gegevens niet vermeld zijn, gebruik null

INTRODUCTIE:
- Schrijf een professionele samenvatting van 2-4 zinnen over de kandidaat
- Beschrijf expertise, werkervaring, en specialisaties

VAARDIGHEDEN:
- Schat het vaardigheidsniveau in (1=beginner, 5=expert) op basis van jaren ervaring, projecten, en certificeringen
- Onderscheid harde vaardigheden (technisch, tools, methodologieën) en zachte vaardigheden (communicatie, leiderschap, samenwerking)
- Geef bij evidence de specifieke tekst uit het CV die het niveau rechtvaardigt

WERKERVARING:
- Lijst ALLE werkposities chronologisch (meest recent eerst)
- Gebruik period.start en period.end als strings: "YYYY-MM" of "YYYY" formaat
- Gebruik "heden" als de positie nog actueel is
- Lijst alle verantwoordelijkheden en taken als aparte strings in responsibilities[]
- Als geen taken beschreven zijn, gebruik een lege array []

OPLEIDING:
- Lijst alle formele opleidingen (MBO, HBO, WO, universiteit)
- year als string: "2012" of "2005-2006" voor periodes
- institution mag null zijn als niet vermeld

CURSUSSEN:
- Lijst alle korte cursussen, trainingen, en workshops apart van opleidingen
- Bijv. "VCA VOL", "BHV", "Cursus Brandveiligheid", "LEAN methodiek"

CERTIFICERINGEN:
- Lijst formele certificeringen apart: "AWS Solutions Architect", "Prince2 Practitioner", "PMP"
- Onderscheid van cursussen: certificeringen zijn formele kwalificaties met erkenning

TALEN:
- Gebruik CEFR-niveaus (A1, A2, B1, B2, C1, C2), "native", of "moedertaal"
- Als niveau niet expliciet vermeld, schat in op basis van context

AFGELEIDE VELDEN (voor matching met vacatures):
- totalYearsExperience: bereken het totale aantal jaren werkervaring op basis van de periodes. Rond af op geheel getal. Null als niet te bepalen.
- highestEducationLevel: classificeer het hoogst behaalde opleidingsniveau als "MBO", "HBO", "WO", of "PhD". Gebruik null als niet te bepalen. Let op: "Propedeuse HBO" = MBO niveau (niet afgerond). "M.T.S." = MBO. "Universiteit" / "MSc" / "Master" = WO.
- industries: lijst van sectoren/branches waar de kandidaat heeft gewerkt. Bijv: "Overheid", "Bouw", "IT", "Finance", "Zorg", "Vastgoed", "Retail", "Energie", "Transport".
- preferredContractType: als het CV een voorkeur vermeldt (freelance, interim, ZZP, vast, detachering), gebruik die. Anders null.
- preferredWorkArrangement: als het CV een voorkeur vermeldt (remote, hybride, op locatie), gebruik die. Anders null.

Wees nauwkeurig en volledig. Extraheer ALLES uit het CV. Als informatie ontbreekt, gebruik null.`;

/** Extract text from a Word (.docx) buffer */
async function extractWordText(buffer: Buffer): Promise<string> {
  const result = await mammoth.extractRawText({ buffer });
  return result.value;
}

/** Parse a CV from a file buffer (PDF or Word) */
export async function parseCV(
  fileBuffer: Buffer,
  mimeType:
    | "application/pdf"
    | "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
): Promise<ParsedCV> {
  if (mimeType === "application/pdf") {
    const { output } = await withRetry(
      () =>
        generateText({
          model: geminiFlash,
          output: Output.object({ schema: parsedCVSchema }),
          system: SYSTEM_PROMPT,
          messages: [
            {
              role: "user",
              content: [
                { type: "file", data: fileBuffer, mediaType: "application/pdf" },
                { type: "text", text: "Analyseer dit CV en extraheer alle informatie." },
              ],
            },
          ],
          providerOptions: { google: { structuredOutputs: true } },
        }),
      { label: "CV Parser (PDF)" },
    );

    return output as ParsedCV;
  }

  // Word document: extract text first, then send as plain text
  const text = await extractWordText(fileBuffer);

  const { output } = await withRetry(
    () =>
      generateText({
        model: geminiFlash,
        output: Output.object({ schema: parsedCVSchema }),
        system: SYSTEM_PROMPT,
        prompt: `Analyseer dit CV en extraheer alle informatie.\n\n${text}`,
        providerOptions: { google: { structuredOutputs: true } },
      }),
    { label: "CV Parser (Word)" },
  );

  return output as ParsedCV;
}

