```typescript
// Next.js API Route: /api/whatsapp/webhook
import type { NextApiRequest, NextApiResponse } from 'next';
import axios from 'axios';

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method === 'GET') {
    // Webhook verification
    const mode = req.query['hub.mode'];
    const token = req.query['hub.verify_token'];
    const challenge = req.query['hub.challenge'];

    if (mode === 'subscribe' && token === process.env.VERIFY_TOKEN) {
      res.status(200).send(challenge);
    } else {
      res.status(403).end();
    }
    return;
  }

  if (req.method === 'POST') {
    const { entry } = req.body;

    for (const change of entry[0].changes) {
      if (change.field === 'messages') {
        const message = change.value.messages[0];

        if (message.type === 'document') {
          const mediaId = message.document.id;

          // Fetch media URL
          const mediaResponse = await axios.get(
            `https://graph.facebook.com/v19.0/${mediaId}`,
            {
              headers: { Authorization: `Bearer ${process.env.WHATSAPP_TOKEN}` }
            }
          );

          // Download document
          const docUrl = mediaResponse.data.url;
          const docResponse = await axios.get(docUrl, {
            headers: { Authorization: `Bearer ${process.env.WHATSAPP_TOKEN}` },
            responseType: 'arraybuffer'
          });

          // Process CV
          const analysis = await analyzeCVDocument(Buffer.from(docResponse.data));

          // Send result back
          await axios.post(
            `https://graph.facebook.com/v19.0/${process.env.PHONE_NUMBER_ID}/messages`,
            {
              messaging_product: 'whatsapp',
              to: message.from,
              type: 'text',
              text: { body: `CV Analysis:\n\n${analysis}` }
            },
            {
              headers: { Authorization: `Bearer ${process.env.WHATSAPP_TOKEN}` }
            }
          );
        }
      }
    }

    res.status(200).end();
  }
}
```

**Pros**:
- **Zero ban risk** (official API)
- Production-ready
- Meta support
- Excellent documentation
- Compliance built-in

**Cons**:
- **Cannot use personal WhatsApp account**
- Business verification required
- More complex setup
- Webhook infrastructure needed
- Per-message costs (small for low volume)

