    // Message retry cache
    msgRetryCounterCache: new NodeCache(),

    // Generate high-quality link previews
    generateHighQualityLinkPreview: true,
  });

  // CRITICAL: Save credentials on every update
  sock.ev.on('creds.update', saveCreds);

  return sock;
