### Production Setup (Database-Based)

```typescript
import { proto } from '@whiskeysockets/baileys';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

interface AuthState {
  creds: any;
  keys: {
    get: (type: string, ids: string[]) => Promise<{ [id: string]: any }>;
    set: (data: { [id: string]: any }) => Promise<void>;
  };
}

async function useDatabaseAuth(sessionId: string): Promise<AuthState> {
  // Load credentials from database
  const session = await prisma.session.findUnique({
    where: { id: sessionId },
    include: { keys: true }
  });

  const creds = session?.creds 
    ? JSON.parse(session.creds) 
    : initAuthCreds();

  return {
    creds,
    keys: {
      get: async (type, ids) => {
        const data: { [id: string]: any } = {};
        const records = await prisma.authKey.findMany({
          where: { 
            sessionId,
            type,
            keyId: { in: ids }
          }
        });

        for (const record of records) {
          data[record.keyId] = JSON.parse(record.value);
        }
        return data;
      },

      set: async (data) => {
        // CRITICAL: Persist every key update immediately
        const operations = Object.entries(data).map(([keyId, value]) => 
          prisma.authKey.upsert({
            where: { 
              sessionId_type_keyId: { 
                sessionId, 
                type: 'auth', 
                keyId 
              }
            },
            update: { value: JSON.stringify(value) },
            create: { 
              sessionId, 
              type: 'auth', 
              keyId, 
              value: JSON.stringify(value) 
            }
          })
        );

        await Promise.all(operations);

        // Update credentials
        await prisma.session.update({
          where: { id: sessionId },
          data: { 
            creds: JSON.stringify(creds),
            updatedAt: new Date()
          }
        });
      }
    }
  };
}
```

## 3. Media Download - Documents, PDFs, Images

### Receiving and Downloading Document Attachments

```typescript
import { 
  downloadMediaMessage, 
  getContentType,
  proto
} from '@whiskeysockets/baileys';
import fs from 'fs';
import path from 'path';

sock.ev.on('messages.upsert', async ({ messages, type }) => {
  if (type !== 'notify') return;

  for (const msg of messages) {
    if (!msg.message) continue;

    const messageType = getContentType(msg.message);
    console.log(`Received message type: ${messageType}`);

    // Handle document messages (PDF, DOCX, etc.)
    if (messageType === 'documentMessage') {
      const document = msg.message.documentMessage;
      console.log(`Document received: ${document?.fileName}`);
      console.log(`MIME type: ${document?.mimetype}`);
      console.log(`Size: ${document?.fileLength} bytes`);

      try {
        // Download as buffer (for small files)
        const buffer = await downloadMediaMessage(
          msg,
          'buffer',
          {},
          { 
            logger,
            reuploadRequest: sock.updateMediaMessage
          }
        );

        // Save to disk
        const fileName = document?.fileName || `document_${Date.now()}`;
        const filePath = path.join('./downloads', fileName);
        fs.writeFileSync(filePath, buffer);
        console.log(`Saved to: ${filePath}`);

      } catch (error) {
        console.error('Media download failed:', error);
      }
    }

    // Handle document as stream (for large files)
    if (messageType === 'documentMessage') {
      const document = msg.message.documentMessage;

      try {
        const stream = await downloadMediaMessage(
          msg,
          'stream',
          {},
          { 
            logger,
            reuploadRequest: sock.updateMediaMessage
          }
        );

        const fileName = document?.fileName || `document_${Date.now()}`;
        const filePath = path.join('./downloads', fileName);
        const writeStream = fs.createWriteStream(filePath);

        stream.pipe(writeStream);

        await new Promise((resolve, reject) => {
          writeStream.on('finish', resolve);
          writeStream.on('error', reject);
        });

        console.log(`Streamed to: ${filePath}`);

      } catch (error) {
        console.error('Stream download failed:', error);
      }
    }

    // Handle images
    if (messageType === 'imageMessage') {
      const buffer = await downloadMediaMessage(
        msg,
        'buffer',
        {},
        { logger, reuploadRequest: sock.updateMediaMessage }
      );

      const fileName = `image_${Date.now()}.jpg`;
      fs.writeFileSync(`./downloads/${fileName}`, buffer);
    }

    // Handle videos
    if (messageType === 'videoMessage') {
      const buffer = await downloadMediaMessage(
        msg,
        'buffer',
        {},
        { logger, reuploadRequest: sock.updateMediaMessage }
      );

      const fileName = `video_${Date.now()}.mp4`;
      fs.writeFileSync(`./downloads/${fileName}`, buffer);
    }
  }
});
