## 5. Reconnection Handling - Keep Connection Alive

### Robust Connection Handler

```typescript
import { Boom } from '@hapi/boom';
import { DisconnectReason } from '@whiskeysockets/baileys';

async function startBot() {
  const sock = await connectToWhatsApp();

  sock.ev.on('connection.update', async (update) => {
    const { connection, lastDisconnect, qr } = update;

    // QR code for pairing
    if (qr) {
      console.log('Scan this QR code:', qr);
    }

    // Connection opened successfully
    if (connection === 'open') {
      console.log('✅ Connected to WhatsApp');
    }

    // Connection closed - handle reconnection
    if (connection === 'close') {
      const statusCode = (lastDisconnect?.error as Boom)?.output?.statusCode;
      const reason = lastDisconnect?.error;

      console.log('Connection closed:', reason);

      // Handle different disconnect reasons
      switch (statusCode) {
        case DisconnectReason.loggedOut:
          console.log('❌ Device logged out. Delete auth folder and scan QR again.');
          // DO NOT reconnect - user must scan QR again
          process.exit(1);
          break;

        case DisconnectReason.restartRequired:
          console.log('🔄 Restart required, reconnecting...');
          startBot(); // Create new socket
          break;

        case DisconnectReason.timedOut:
          console.log('⏱️ Connection timed out, reconnecting...');
          setTimeout(startBot, 5000); // Wait 5s before reconnect
          break;

        case DisconnectReason.badSession:
          console.log('❌ Bad session, delete auth and restart');
          // Clean up auth state and restart
          process.exit(1);
          break;

        case 428: // Too many reconnect attempts
          console.log('⚠️ Too many reconnects, waiting 60s...');
          setTimeout(startBot, 60_000);
          break;

        default:
          console.log('🔄 Reconnecting...');
          setTimeout(startBot, 3000);
      }
    }

    // Connection state changes
    if (connection === 'connecting') {
      console.log('🔌 Connecting to WhatsApp...');
    }
  });

  // Handle credential updates
  sock.ev.on('creds.update', async () => {
    console.log('🔑 Credentials updated');
    // Auto-saved by useMultiFileAuthState or your custom handler
  });

  return sock;
}

// Start with error handling
startBot().catch(error => {
  console.error('Fatal error:', error);
  process.exit(1);
});
```

## 6. Error Handling - Common Errors

### Comprehensive Error Handler

```typescript
import { proto } from '@whiskeysockets/baileys';

// Message send with retry
async function sendMessageWithRetry(
  sock: any,
  jid: string,
  content: any,
  maxRetries = 3
) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const result = await sock.sendMessage(jid, content);
      return result;
    } catch (error) {
      console.error(`Send attempt ${attempt} failed:`, error);

      if (attempt === maxRetries) {
        throw new Error(`Failed after ${maxRetries} attempts`);
      }

      // Exponential backoff
      await delay(1000 * Math.pow(2, attempt));
    }
  }
}

// Global error handling
sock.ev.on('messages.upsert', async ({ messages }) => {
  for (const msg of messages) {
    try {
      await handleMessage(msg);
    } catch (error) {
      console.error('Message handling error:', error);

      // Send error notification to admin
      await sock.sendMessage(
        ADMIN_JID,
        { text: `Error processing message: ${error.message}` }
      );
    }
  }
});

// Media download with fallback
async function safeDownloadMedia(msg: proto.IWebMessageInfo) {
  try {
    const buffer = await downloadMediaMessage(
      msg,
      'buffer',
      {},
      { logger, reuploadRequest: sock.updateMediaMessage }
    );
    return buffer;
  } catch (error) {
    console.error('Primary download failed, trying without reupload...');

    try {
      const buffer = await downloadMediaMessage(
        msg,
        'buffer',
        {},
        { logger }
      );
      return buffer;
    } catch (fallbackError) {
      console.error('Media download failed completely:', fallbackError);
      throw new Error('Media no longer available on WhatsApp servers');
    }
  }
}
```

### Common Error Codes

| Code | Reason | Action |
|------|--------|--------|
| 401 | `loggedOut` | Delete auth, scan QR again |
| 408 | `timedOut` | Reconnect after delay |
| 428 | Too many reconnects | Wait 60s, then reconnect |
| 440 | `badSession` | Clear auth state |
| 500 | `restartRequired` | Create new socket |
| 515 | Connection needs restart | Recreate connection |

