### Production Setup (Database-Based)

```typescript
import { proto } from '@whiskeysockets/baileys';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

interface AuthState {
  creds: any;
  keys: {
    get: (type: string, ids: string[]) => Promise<{ [id: string]: any }>;
    set: (data: { [id: string]: any }) => Promise<void>;
  };
}

async function useDatabaseAuth(sessionId: string): Promise<AuthState> {
  // Load credentials from database
  const session = await prisma.session.findUnique({
    where: { id: sessionId },
    include: { keys: true }
  });

  const creds = session?.creds 
    ? JSON.parse(session.creds) 
    : initAuthCreds();

  return {
    creds,
    keys: {
      get: async (type, ids) => {
        const data: { [id: string]: any } = {};
        const records = await prisma.authKey.findMany({
          where: { 
            sessionId,
            type,
            keyId: { in: ids }
          }
        });

        for (const record of records) {
          data[record.keyId] = JSON.parse(record.value);
        }
        return data;
      },

      set: async (data) => {
        // CRITICAL: Persist every key update immediately
        const operations = Object.entries(data).map(([keyId, value]) => 
          prisma.authKey.upsert({
            where: { 
              sessionId_type_keyId: { 
                sessionId, 
                type: 'auth', 
                keyId 
              }
            },
            update: { value: JSON.stringify(value) },
            create: { 
              sessionId, 
              type: 'auth', 
              keyId, 
              value: JSON.stringify(value) 
            }
          })
        );

        await Promise.all(operations);

        // Update credentials
        await prisma.session.update({
          where: { id: sessionId },
          data: { 
            creds: JSON.stringify(creds),
            updatedAt: new Date()
          }
        });
      }
    }
  };
}
```

