## 8. Rate Limiting - Avoid Getting Banned

### Best Practices from baileys-antiban

```typescript
// Rate limiting configuration
const RATE_LIMITS = {
  maxPerMinute: 8,
  maxPerHour: 200,
  maxPerDay: 1500,
  minDelayMs: 2000, // Minimum 2s between messages
  maxDelayMs: 8000  // Maximum 8s between messages
};

class RateLimiter {
  private messageCount = {
    minute: 0,
    hour: 0,
    day: 0
  };

  private lastReset = {
    minute: Date.now(),
    hour: Date.now(),
    day: Date.now()
  };

  private lastMessageTime = 0;

  async waitForSlot(): Promise<void> {
    // Reset counters if time windows passed
    const now = Date.now();

    if (now - this.lastReset.minute > 60_000) {
      this.messageCount.minute = 0;
      this.lastReset.minute = now;
    }

    if (now - this.lastReset.hour > 3600_000) {
      this.messageCount.hour = 0;
      this.lastReset.hour = now;
    }

    if (now - this.lastReset.day > 86400_000) {
      this.messageCount.day = 0;
      this.lastReset.day = now;
    }

    // Check limits
    if (this.messageCount.minute >= RATE_LIMITS.maxPerMinute) {
      const waitTime = 60_000 - (now - this.lastReset.minute);
      console.log(`⏳ Rate limit: waiting ${waitTime}ms`);
      await delay(waitTime);
      this.messageCount.minute = 0;
      this.lastReset.minute = Date.now();
    }

    if (this.messageCount.hour >= RATE_LIMITS.maxPerHour) {
      throw new Error('Hourly rate limit reached');
    }

    if (this.messageCount.day >= RATE_LIMITS.maxPerDay) {
      throw new Error('Daily rate limit reached');
    }

    // Human-like delay between messages
    const timeSinceLastMessage = now - this.lastMessageTime;
    const minDelay = RATE_LIMITS.minDelayMs;

    if (timeSinceLastMessage < minDelay) {
      const randomDelay = minDelay + Math.random() * (RATE_LIMITS.maxDelayMs - minDelay);
      await delay(randomDelay);
    }

    this.messageCount.minute++;
    this.messageCount.hour++;
    this.messageCount.day++;
    this.lastMessageTime = Date.now();
  }
}

const rateLimiter = new RateLimiter();

// Use before sending messages
async function sendMessageSafely(jid: string, content: any) {
  await rateLimiter.waitForSlot();
  return await sock.sendMessage(jid, content);
}
```

### Anti-Ban Best Practices

1. **Warm Up New Numbers**
   - Day 1: Send 5-10 messages
   - Day 2: Send 20-30 messages
   - Day 3+: Gradually increase to normal volume
   - Never send 1000 messages on day 1

2. **Use Real Phone Numbers**
   - Virtual/VOIP numbers get banned faster
   - Use verified business accounts when possible

3. **Avoid Identical Messages**
   ```typescript
   const variations = [
     'Hello {name}!',
     'Hi {name}!',
     'Hey {name}!',
     'Greetings {name}!'
   ];

   function varyMessage(template: string, name: string): string {
     const random = variations[Math.floor(Math.random() * variations.length)];
     return random.replace('{name}', name);
   }
   ```

4. **Respect User Responses**
   ```typescript
   const userStates = new Map<string, { lastMessageTime: number, messageCount: number }>();

   function shouldMessageUser(jid: string): boolean {
     const state = userStates.get(jid);

     if (!state) return true;

     // Don't spam users
     const hoursSinceLastMessage = (Date.now() - state.lastMessageTime) / 3600_000;

     if (hoursSinceLastMessage < 24 && state.messageCount > 3) {
       return false; // Don't send more than 3 messages per day to same user
     }

     return true;
   }
   ```

5. **Monitor Health Metrics**
   ```typescript
   interface BotHealth {
     messagesPerHour: number;
     errorRate: number;
     reconnectCount: number;
   }

   const health: BotHealth = {
     messagesPerHour: 0,
     errorRate: 0,
     reconnectCount: 0
   };

   // Pause bot if health is bad
   if (health.errorRate > 0.3 || health.reconnectCount > 5) {
     console.log('⚠️ Bot health degraded, pausing for 1 hour');
     await delay(3600_000);
   }
   ```

