  fetchLatestBaileysVersion
} from '@whiskeysockets/baileys';
import { Boom } from '@hapi/boom';
import pino from 'pino';
import fs from 'fs';
import path from 'path';

const logger = pino({ level: 'info' });

// Rate limiter
class RateLimiter {
  private counts = { minute: 0, hour: 0, day: 0 };
  private resets = { minute: Date.now(), hour: Date.now(), day: Date.now() };
  private lastMessage = 0;

  async wait() {
    const now = Date.now();

    // Reset counters
    if (now - this.resets.minute > 60_000) {
      this.counts.minute = 0;
      this.resets.minute = now;
    }

    // Check limits
    if (this.counts.minute >= 8) {
      await delay(60_000 - (now - this.resets.minute));
      this.counts.minute = 0;
    }

    // Human-like delay
    const timeSince = now - this.lastMessage;
    if (timeSince < 2000) {
      await delay(2000 + Math.random() * 6000);
    }

    this.counts.minute++;
    this.lastMessage = Date.now();
  }
}

const rateLimiter = new RateLimiter();

async function startWhatsAppBot() {
  const { state, saveCreds } = await useMultiFileAuthState('auth_info_baileys');
  const { version } = await fetchLatestBaileysVersion();

  const sock = makeWASocket({
    version,
    logger,
    printQRInTerminal: true,
    auth: state,
    connectTimeoutMs: 60_000,
    keepAliveIntervalMs: 30_000,
  });

  // Save credentials
  sock.ev.on('creds.update', saveCreds);

  // Connection handling
  sock.ev.on('connection.update', async (update) => {
    const { connection, lastDisconnect } = update;

    if (connection === 'open') {
      console.log('✅ Connected to WhatsApp');
    }

    if (connection === 'close') {
      const statusCode = (lastDisconnect?.error as Boom)?.output?.statusCode;

      if (statusCode === DisconnectReason.loggedOut) {
        console.log('❌ Logged out');
        process.exit(1);
      } else if (statusCode === 428) {
        console.log('⏳ Too many reconnects, waiting...');
        await delay(60_000);
        startWhatsAppBot();
      } else {
        console.log('🔄 Reconnecting...');
        await delay(3000);
        startWhatsAppBot();
      }
    }
  });

  // Message handler
  sock.ev.on('messages.upsert', async ({ messages, type }) => {
    if (type !== 'notify') return;

    for (const msg of messages) {
      if (!msg.message) continue;
      if (msg.key.fromMe) continue; // Ignore own messages

      const messageType = getContentType(msg.message);
      const from = msg.key.remoteJid!;

      try {
        // Handle text messages
        if (messageType === 'conversation' || messageType === 'extendedTextMessage') {
          const text = msg.message.conversation || msg.message.extendedTextMessage?.text;
          console.log(`📨 Text from ${from}: ${text}`);

          // Echo back
          await rateLimiter.wait();
          await sock.sendMessage(from, { text: `You said: ${text}` }, { quoted: msg });
        }

        // Handle document messages
        if (messageType === 'documentMessage') {
          const doc = msg.message.documentMessage;
          console.log(`📄 Document: ${doc?.fileName}`);

          const buffer = await downloadMediaMessage(
            msg,
            'buffer',
            {},
            { logger, reuploadRequest: sock.updateMediaMessage }
          );

          const fileName = doc?.fileName || `doc_${Date.now()}`;
          fs.writeFileSync(path.join('./downloads', fileName), buffer);

          await rateLimiter.wait();
          await sock.sendMessage(from, { 
            text: `✅ Downloaded: ${fileName}` 
          }, { quoted: msg });
        }

      } catch (error) {
        console.error('Error handling message:', error);
      }
    }
  });

  return sock;
}

// Start bot with auto-restart
async function main() {
  while (true) {
    try {
      await startWhatsAppBot();
      await new Promise(() => {}); // Keep alive
    } catch (error) {
      console.error('Bot crashed:', error);
      await delay(10_000);
    }
  }
}

main();
